module pulse_detect(
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);
// Define state parameter values
parameter S0 = 2'b00;
parameter S1 = 2'b01;
parameter S2 = 2'b10;
parameter S3 = 2'b11;
// Define state register
reg [1:0] state;
// Define next state logic
reg [1:0] next_state;
// Define output logic
always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        state <= S0;
        data_out <= 0;
    end else begin
        state <= next_state;
        case(state)
            S0: begin
                if (data_in == 1) begin
                    next_state <= S1;
                    data_out <= 0;
                end else begin
                    next_state <= S0;
                    data_out <= 0;
                end
            end
            S1: begin
                if (data_in == 1) begin
                    next_state <= S2;
                    data_out <= 0;
                end else begin
                    next_state <= S0;
                    data_out <= 0;
                end
            end
            S2: begin
                if (data_in == 0) begin
                    next_state <= S3;
                    data_out <= 0;
                end else begin
                    next_state <= S0;
                    data_out <= 0;
                end
            end
            S3: begin
                if (data_in == 0) begin
                    next_state <= S0;
                    data_out <= 0;
                end else begin
                    next_state <= S0;
                    data_out <= 1;
                end
            end
            default: begin
                next_state <= S0;
                data_out <= 0;
            end
        endcase
    end
end
endmodule
